import { useState, useEffect } from "react";

function App() {
  const [tarefa, setTarefa] = useState("");

  const [lista, setLista] = useState(() => {
    const tarefasSalvas = localStorage.getItem("tarefas");
    return tarefasSalvas ? JSON.parse(tarefasSalvas) : [];
  });

  useEffect(() => {
    localStorage.setItem("tarefas", JSON.stringify(lista));
  }, [lista]);

  function adicionarTarefa() {
    if (tarefa.trim() === "") return;

    const novaTarefa = {
      texto: tarefa,
      concluida: false
    };

    setLista([...lista, novaTarefa]);
    setTarefa("");
  }

  function removerTarefa(index) {
    const novaLista = lista.filter((_, i) => i !== index);
    setLista(novaLista);
  }

  function toggleTarefa(index) {
    const novaLista = lista.map((item, i) => {
      if (i === index) {
        return { ...item, concluida: !item.concluida };
      }
      return item;
    });

    setLista(novaLista);
  }

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h1 style={styles.title}>📝 To-Do List</h1>

        <div style={styles.inputArea}>
          <input
            style={styles.input}
            value={tarefa}
            onChange={(e) => setTarefa(e.target.value)}
            placeholder="Digite uma tarefa..."
          />

          <button style={styles.addButton} onClick={adicionarTarefa}>
            +
          </button>
        </div>

        <ul style={styles.lista}>
          {lista.map((item, index) => (
            <li
              key={index}
              style={{
                ...styles.item,
                background: item.concluida ? "#e0ffe0" : "#fff"
              }}
            >
              <span
                style={{
                  ...styles.texto,
                  textDecoration: item.concluida ? "line-through" : "none",
                  color: item.concluida ? "#888" : "#000"
                }}
              >
                {item.texto}
              </span>

              <div style={styles.actions}>
                <button
                  style={{
                    ...styles.checkButton,
                    background: item.concluida ? "#555" : "#28a745"
                  }}
                  onClick={() => toggleTarefa(index)}
                >
                  ✔
                </button>

                <button
                  style={styles.deleteButton}
                  onClick={() => removerTarefa(index)}
                >
                  ✖
                </button>
              </div>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

const styles = {
  page: {
    background: "#f4f6f8",
    minHeight: "100vh",
    display: "flex",
    justifyContent: "center",
    alignItems: "center"
  },
  container: {
    background: "#fff",
    padding: 20,
    borderRadius: 10,
    boxShadow: "0 4px 10px rgba(0,0,0,0.1)",
    width: 350
  },
  title: {
    textAlign: "center",
    marginBottom: 20
  },
  inputArea: {
    display: "flex",
    gap: 10,
    marginBottom: 20
  },
  input: {
    flex: 1,
    padding: 10,
    borderRadius: 5,
    border: "1px solid #ccc"
  },
  addButton: {
    padding: "10px 15px",
    borderRadius: 5,
    border: "none",
    background: "#007bff",
    color: "#fff",
    fontSize: 18,
    cursor: "pointer"
  },
  lista: {
    listStyle: "none",
    padding: 0
  },
  item: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: 10,
    borderRadius: 5,
    marginBottom: 10,
    transition: "0.2s"
  },
  texto: {},
  actions: {
    display: "flex",
    gap: 5
  },
  checkButton: {
    border: "none",
    color: "#fff",
    padding: "5px 8px",
    borderRadius: 5,
    cursor: "pointer"
  },
  deleteButton: {
    background: "#dc3545",
    color: "#fff",
    border: "none",
    padding: "5px 8px",
    borderRadius: 5,
    cursor: "pointer"
  }
};

export default App;
